%%%%%%%%%% Function vrnInfRead2.m %%%%%%%%%%% Varian Information reader, ver.2% Kei Nakamura% Created on Thursday, March 30th 2006.% Modified on Sunday, April 16th 2006.%% function [ttl,dat] = vrnInfRead(fname)% returns the name of the columns (title) and a matrix% containing the whole data of the log file.function [ttl,dat,cmp] = vrnInfRead2(fname)  %function headerfid = fopen(fname);     % file open('name','permission')   lin1 = fgetl(fid);      % read first line (trash)for i=1:6    lin = fgetl(fid);    dbl = double(lin);    k = find(dbl==61);  % find '='      dat(i) = str2num(lin(k+1:end));    ttl{i} = lin(1:k-1);endfor i=1:9    lin = fgetl(fid);endlin = fgetl(fid);dbl = double(lin);k = find(dbl==34); % find "dbl = dbl(k(1)+1:end-1);lin = lin(k(1)+1:end-1);p = find(dbl==44); % find ,[py px] = size(p);cmp{1,1} = 1;cmp{1,2} = lin(1:p(1)-1);for i=1:px-1    cmp{i+1,1} = i+1;    cmp{i+1,2} = lin(p(i)+1:p(i+1)-1);endcmp{px+1,1} = px+1;cmp{px+1,2} = lin(p(px)+1:end);fclose(fid);
